# Let's write a C# program to deeply analyze the binlog for more details
cat > /tmp/analyze_binlog.cs << 'CSHARPEOF'
using System;
using System.IO;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

class Program
{
    static void Main(string[] args)
    {
        var build = BinaryLog.ReadBuild(args[0]);

        // Get all errors
        var errors = build.FindChildrenRecursive<Error>().ToList();
        // Get all warnings
        var warnings = build.FindChildrenRecursive<Warning>().ToList();
        // Get all projects
        var projects = build.FindChildrenRecursive<Project>().ToList();

        Console.WriteLine("=== BUILD SUMMARY ===");
        Console.WriteLine($"Build succeeded: {build.Succeeded}");
        Console.WriteLine($"Total projects: {projects.Count}");
        Console.WriteLine($"Total errors: {errors.Count}");
        Console.WriteLine($"Total warnings: {warnings.Count}");

        Console.WriteLine("\n=== PROJECTS ===");
        foreach (var p in projects)
        {
            Console.WriteLine($"  Project: {p.Name} | Succeeded: {p.Succeeded}");
        }

        Console.WriteLine("\n=== ALL ERRORS ===");
        foreach (var e in errors)
        {
            var projectName = GetParentProject(e)?.Name ?? "unknown";
            Console.WriteLine($"  [{projectName}] {e.Code}: {e.Text}");
            if (!string.IsNullOrEmpty(e.File))
                Console.WriteLine($"    File: {e.File} Line: {e.LineNumber}");
        }

        Console.WriteLine("\n=== ALL WARNINGS ===");
        foreach (var w in warnings)
        {
            var projectName = GetParentProject(w)?.Name ?? "unknown";
            Console.WriteLine($"  [{projectName}] {w.Code}: {w.Text}");
        }
    }

    static Project GetParentProject(BaseNode node)
    {
        var current = node.Parent;
        while (current != null)
        {
            if (current is Project p) return p;
            current = (current as BaseNode)?.Parent;
        }
        return null;
    }
}
