cat > /tmp/binlog-analyzer/Program.cs << 'CSHARPEOF'
using System;
using System.IO;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

class Program
{
    static void Main(string[] args)
    {
        var build = BinaryLog.ReadBuild(args[0]);

        var errors = build.FindChildrenRecursive<Error>().ToList();
        var warnings = build.FindChildrenRecursive<Warning>().ToList();
        var projects = build.FindChildrenRecursive<Project>().ToList();

        Console.WriteLine("=== BUILD SUMMARY ===");
        Console.WriteLine($"Build succeeded: {build.Succeeded}");
        Console.WriteLine($"Total projects: {projects.Count}");
        Console.WriteLine($"Total errors: {errors.Count}");
        Console.WriteLine($"Total warnings: {warnings.Count}");

        Console.WriteLine("\n=== PROJECTS ===");
        foreach (var p in projects)
        {
            var hasErrors = p.FindChildrenRecursive<Error>().Any();
            Console.WriteLine($"  Project: {p.Name} | HasErrors: {hasErrors}");

            // Show project references
            var items = p.FindChildrenRecursive<Item>().Where(i => i.Name == "ProjectReference").ToList();
            foreach (var item in items)
            {
                Console.WriteLine($"    -> ProjectReference: {item.Text}");
            }
        }

        Console.WriteLine("\n=== ALL ERRORS (grouped by project) ===");
        var errorsByProject = errors.GroupBy(e => GetParentProject(e)?.Name ?? "unknown");
        foreach (var group in errorsByProject)
        {
            Console.WriteLine($"\n  Project: {group.Key}");
            foreach (var e in group)
            {
                Console.WriteLine($"    {e.Code}: {e.Text}");
                if (!string.IsNullOrEmpty(e.File))
                    Console.WriteLine($"      File: {e.File} Line: {e.LineNumber}");
            }
        }

        if (warnings.Any())
        {
            Console.WriteLine("\n=== WARNINGS ===");
            foreach (var w in warnings)
            {
                var projectName = GetParentProject(w)?.Name ?? "unknown";
                Console.WriteLine($"  [{projectName}] {w.Code}: {w.Text}");
            }
        }

        // Check for dependency structure
        Console.WriteLine("\n=== DEPENDENCY ANALYSIS ===");
        var failedProjects = projects.Where(p => p.FindChildrenRecursive<Error>().Any()).Select(p => p.Name).ToHashSet();
        Console.WriteLine($"Failed projects: {string.Join(", ", failedProjects)}");

        var succeededProjects = projects.Where(p => !p.FindChildrenRecursive<Error>().Any()).Select(p => p.Name).ToHashSet();
        Console.WriteLine($"Succeeded projects: {string.Join(", ", succeededProjects)}");
    }

    static Project GetParentProject(BaseNode node)
    {
        var current = node.Parent;
        while (current != null)
        {
            if (current is Project p) return p;
            current = (current as BaseNode)?.Parent;
        }
        return null;
    }
}
