# Let's get more detail - extract the source file content and project references from the binlog
cat > /tmp/binlog-analyzer/Program.cs << 'CSHARPEOF'
using System;
using System.IO;
using System.Linq;
using System.Collections.Generic;
using Microsoft.Build.Logging.StructuredLogger;

class Program
{
    static void Main(string[] args)
    {
        var build = BinaryLog.ReadBuild(args[0]);

        // Extract all source file content embedded in the binlog
        Console.WriteLine("=== SEARCHING FOR SOURCE FILE CONTENT & PROJECT DETAILS ===\n");

        // Get messages that might contain source info
        var messages = build.FindChildrenRecursive<Message>().ToList();

        // Get all NamedNode items to find package references
        var allItems = build.FindChildrenRecursive<Item>().ToList();
        var packageRefs = allItems.Where(i => 
            i.Name?.Contains("PackageReference") == true || 
            i.Name?.Contains("Package") == true
        ).ToList();

        Console.WriteLine("=== PACKAGE REFERENCES FOUND ===");
        foreach (var pr in packageRefs.DistinctBy(p => p.Text).Take(50))
        {
            Console.WriteLine($"  {pr.Name}: {pr.Text}");
        }

        // Get project references
        var projRefs = allItems.Where(i => i.Name?.Contains("ProjectReference") == true).ToList();
        Console.WriteLine("\n=== PROJECT REFERENCES ===");
        foreach (var pr in projRefs.DistinctBy(p => p.Text).Take(20))
        {
            var project = GetParentProject(pr)?.Name ?? "unknown";
            Console.WriteLine($"  [{project}] {pr.Name}: {pr.Text}");
        }

        // Look at the AddItem/folder nodes
        var folders = build.FindChildrenRecursive<Folder>().ToList();
        Console.WriteLine($"\n=== FOLDER NODES ({folders.Count}) ===");
        foreach (var f in folders.Where(f => f.Name?.Contains("Items") == true || f.Name?.Contains("Reference") == true).Take(30))
        {
            var project = GetParentProject(f)?.Name ?? "unknown";
            Console.WriteLine($"  [{project}] Folder: {f.Name}");
            foreach (var child in f.Children.OfType<Item>().Take(10))
            {
                Console.WriteLine($"    -> {child.Name}: {child.Text}");
                foreach (var meta in child.Children.OfType<Metadata>().Take(5))
                {
                    Console.WriteLine($"       {meta.Name} = {meta.Value}");
                }
            }
        }

        // Look for the actual .csproj content via properties
        var props = build.FindChildrenRecursive<Property>().ToList();
        Console.WriteLine($"\n=== KEY PROPERTIES ===");
        foreach (var p in props.Where(p => 
            p.Name == "TargetFramework" || 
            p.Name == "RootNamespace" ||
