using System;
using System.IO;
using System.Linq;
using System.Collections.Generic;
using Microsoft.Build.Logging.StructuredLogger;

class Program
{
    static void Main(string[] args)
    {
        var build = BinaryLog.ReadBuild(args[0]);

        // Check if source files were created during replay
        Console.WriteLine("=== EMBEDDED FILES / SOURCE TEXT ===");
        var sourceFiles = build.FindChildrenRecursive<SourceFile>().ToList();
        Console.WriteLine($"SourceFile nodes: {sourceFiles.Count}");
        foreach (var sf in sourceFiles.Take(20))
        {
            Console.WriteLine($"  {sf.Name}: {sf.Text}");
        }

        // Look for SourceFilesProjectOutputGroupOutput or similar
        var allNodes = new List<BaseNode>();
        CollectAll(build, allNodes);
        Console.WriteLine($"\nTotal nodes: {allNodes.Count}");

        // Group by type
        var nodeTypes = allNodes.GroupBy(n => n.GetType().Name).OrderByDescending(g => g.Count());
        Console.WriteLine("\n=== NODE TYPES ===");
        foreach (var g in nodeTypes.Take(30))
        {
            Console.WriteLine($"  {g.Key}: {g.Count()}");
        }

        // Look for AddItem nodes with PackageReference
        var addItems = allNodes.OfType<AddItem>().ToList();
        Console.WriteLine($"\n=== ADD ITEMS ({addItems.Count}) ===");
        foreach (var ai in addItems.Take(50))
        {
            var project = GetParentProject(ai)?.Name ?? "unknown";
            Console.WriteLine($"  [{project}] AddItem: {ai.Name} ({ai.Children.Count} children)");
            foreach (var child in ai.Children.OfType<Item>().Take(5))
            {
                Console.WriteLine($"    -> {child.Text}");
                foreach (var meta in child.Children.OfType<Metadata>().Take(5))
                {
                    Console.WriteLine($"       {meta.Name} = {meta.Value}");
                }
            }
        }

        // Look at all NameValueNode items 
        Console.WriteLine("\n=== ITEMS NAMED 'PackageReference' ===");
        var namedNodes = allNodes.OfType<NameValueNode>().Where(n => 
            n.Name?.Contains("PackageReference") == true ||
            n.Value?.Contains("Newtonsoft") == true ||
            n.Name?.Contains("Newtonsoft") == true ||
            n.Text?.Contains("Newtonsoft") == true
        ).ToList();
        foreach (var nn in namedNodes.Take(20))
        {
            Console.WriteLine($"  {nn.GetType().Name}: Name={nn.Name} Value={nn.Value}");
        }

        // Check the Api project dependencies
        Console.WriteLine("\n=== API PROJECT P2P REFERENCES ===");
        var apiProjects = allNodes.OfType<Project>().Where(p => p.Name == "Api.csproj").ToList();
        foreach (var ap in apiProjects.Take(3))
        {
            var refItems = ap.FindChildrenRecursive<Item>().Where(i => 
                i.Name?.Contains("Reference") == true
            ).ToList();
            foreach (var ri in refItems.DistinctBy(r => r.Text).Take(20))
            {
                Console.WriteLine($"  {ri.Name}: {ri.Text}");
            }
        }
    }

    static void CollectAll(BaseNode node, List<BaseNode> result)
    {
        result.Add(node);
        if (node is TreeNode tn)
        {
            foreach (var child in tn.Children.OfType<BaseNode>())
            {
                CollectAll(child, result);
            }
        }
    }

    static Project GetParentProject(BaseNode node)
    {
        var current = node.Parent;
        while (current != null)
        {
            if (current is Project p) return p;
            current = (current as BaseNode)?.Parent;
        }
        return null;
    }
}
