using System.IO;
using System.Linq;
using System.Collections.Generic;
using Microsoft.Build.Logging.StructuredLogger;

class Program
{
    static void Main(string[] args)
    {
        var build = BinaryLog.ReadBuild(args[0]);

        Console.WriteLine("=== EMBEDDED SOURCE FILES ===");
        var sourceFiles = build.FindChildrenRecursive<SourceFile>().ToList();
        Console.WriteLine($"SourceFile nodes: {sourceFiles.Count}");
        foreach (var sf in sourceFiles.Take(20))
        {
            Console.WriteLine($"  {sf.Name}");
        }

        // Look for AddItem nodes
        var allNodes = new List<BaseNode>();
        CollectAll(build, allNodes);

        var addItems = allNodes.OfType<AddItem>().ToList();
        Console.WriteLine($"\n=== ADD ITEMS ({addItems.Count}) ===");
        foreach (var ai in addItems.Take(80))
        {
            var project = GetParentProject(ai)?.Name ?? "unknown";
            Console.WriteLine($"  [{project}] AddItem: {ai.Name}");
            foreach (var child in ai.Children.OfType<Item>().Take(5))
            {
                Console.WriteLine($"    -> {child.Name}: {child.Text}");
                foreach (var meta in child.Children.OfType<Metadata>().Take(3))
                {
                    Console.WriteLine($"       {meta.Name} = {meta.Value}");
                }
            }
        }

        // Look for anything Newtonsoft
        Console.WriteLine("\n=== SEARCHING ALL TEXT FOR 'Newtonsoft' ===");
        var allMessages = build.FindChildrenRecursive<Message>().Where(m => m.Text?.Contains("Newtonsoft") == true).ToList();
        foreach (var m in allMessages.Take(20))
        {
            Console.WriteLine($"  Message: {m.Text?.Substring(0, Math.Min(200, m.Text.Length))}");
        }

        // Check the Api project for its project references 
        Console.WriteLine("\n=== API PROJECT DETAILS ===");
        var apiProjects = allNodes.OfType<Project>().Where(p => p.Name == "Api.csproj").ToList();
        foreach (var ap in apiProjects.Take(1))
        {
            var addItemsForApi = ap.FindChildrenRecursive<AddItem>().ToList();
            foreach (var ai in addItemsForApi)
            {
                Console.WriteLine($"  AddItem: {ai.Name}");
                foreach (var child in ai.Children.OfType<Item>().Take(3))
                {
                    Console.WriteLine($"    -> {child.Name}: {child.Text}");
                }
            }
