using System;
using System.IO;
using System.Linq;
using System.Collections.Generic;
using Microsoft.Build.Logging.StructuredLogger;

class Program
{
    static void Main(string[] args)
    {
        var build = BinaryLog.ReadBuild(args[0]);

        // Find all ArchiveFile nodes by traversing the tree manually
        var archiveFiles = new List<ArchiveFile>();
        CollectArchiveFiles(build, archiveFiles);

        Console.WriteLine($"=== ARCHIVE FILES ({archiveFiles.Count}) ===");
        foreach (var af in archiveFiles)
        {
            bool isInteresting = af.FullPath?.Contains(".csproj") == true || 
                af.FullPath?.Contains(".cs") == true || 
                af.FullPath?.Contains(".sln") == true;

            if (isInteresting)
            {
                Console.WriteLine($"\n--- {af.FullPath} ---");
                Console.WriteLine(af.Text);
            }
            else
            {
                Console.WriteLine($"  (skipped) {af.FullPath}");
            }
        }
    }

    static void CollectArchiveFiles(object node, List<ArchiveFile> result)
    {
        if (node is ArchiveFile af)
        {
            result.Add(af);
        }

        if (node is TreeNode tn)
        {
            foreach (var child in tn.Children)
            {
                CollectArchiveFiles(child, result);
            }
        }
    }
}
