using System;
using System.IO;
using System.Linq;
using System.Collections.Generic;
using Microsoft.Build.Logging.StructuredLogger;

class Program
{
    static void Main(string[] args)
    {
        // Use ReadRecords for lower-level access
        var records = BinaryLog.ReadRecords(args[0]).ToList();
        Console.WriteLine($"Total records: {records.Count}");

        // Group by type
        var byType = records.GroupBy(r => r.Args?.GetType().Name ?? "null").OrderByDescending(g => g.Count());
        Console.WriteLine("\n=== RECORD TYPES ===");
        foreach (var g in byType)
        {
            Console.WriteLine($"  {g.Key}: {g.Count()}");
        }

        // Look for project started events to extract project files
        var projectStarted = records
            .Where(r => r.Args is Microsoft.Build.Framework.ProjectStartedEventArgs)
            .Select(r => r.Args as Microsoft.Build.Framework.ProjectStartedEventArgs)
            .ToList();

        Console.WriteLine($"\n=== PROJECT STARTED EVENTS ({projectStarted.Count}) ===");
        foreach (var ps in projectStarted)
        {
            Console.WriteLine($"  Project: {ps.ProjectFile}");
            Console.WriteLine($"  TargetNames: {ps.TargetNames}");

            // Show items
            if (ps.Items != null)
            {
                Console.WriteLine("  Items:");
                foreach (Microsoft.Build.Framework.DictionaryEntry item in ps.Items)
                {
                    var key = item.Key?.ToString();
                    if (key == "PackageReference" || key == "ProjectReference" || key == "Compile" || key == "Reference")
                    {
                        var val = item.Value;
                        if (val is Microsoft.Build.Framework.ITaskItem taskItem)
                        {
                            Console.WriteLine($"    {key}: {taskItem.ItemSpec}");
                            foreach (string metaName in taskItem.MetadataNames)
                            {
                                if (metaName == "Version" || metaName == "Include")
                                    Console.WriteLine($"      {metaName} = {taskItem.GetMetadata(metaName)}");
                            }
                        }
                        else
                        {
                            Console.WriteLine($"    {key}: {val}");
                        }
                    }
                }
            }
        }
    }
}
