using System;
using System.IO;
using System.Linq;
using System.Collections.Generic;
using Microsoft.Build.Logging.StructuredLogger;

class Program
{
    static void Main(string[] args)
    {
        var build = BinaryLog.ReadBuild(args[0]);

        // Find all AddItem nodes from the _GenerateProjectRestoreGraph targets
        // These contain PackageReference items
        var allNodes = new List<object>();
        CollectAll(build, allNodes);

        // Get all Target nodes
        var targets = allNodes.OfType<Target>().ToList();
        Console.WriteLine($"Total targets: {targets.Count}");

        // Find restore graph targets
        var restoreTargets = targets.Where(t => 
            t.Name?.Contains("RestoreGraph") == true || 
            t.Name?.Contains("Compile") == true ||
            t.Name?.Contains("ResolveReference") == true ||
            t.Name?.Contains("CoreCompile") == true
        ).ToList();

        Console.WriteLine($"\n=== INTERESTING TARGETS ===");
        foreach (var t in restoreTargets)
        {
            var project = GetParentProject(t)?.Name ?? "unknown";
            Console.WriteLine($"  [{project}] Target: {t.Name}");
        }

        // Look at all items from the _GenerateProjectRestoreGraph targets
        Console.WriteLine("\n=== RESTORE GRAPH ITEMS ===");
        foreach (var t in targets.Where(t => t.Name == "_GenerateProjectRestoreGraph"))
        {
            var project = GetParentProject(t)?.Name ?? "unknown";
            Console.WriteLine($"\n  [{project}] {t.Name}:");

            // Get task nodes inside
            var tasks = t.Children.OfType<Task>().ToList();
            foreach (var task in tasks)
            {
                Console.WriteLine($"    Task: {task.Name}");
                // Look at messages in the task
                var msgs = task.FindChildrenRecursive<Message>().ToList();
                foreach (var m in msgs.Where(m => m.Text?.Contains("PackageReference") == true || m.Text?.Contains("ProjectReference") == true))
                {
                    Console.WriteLine($"      {m.Text?.Substring(0, Math.Min(200, m.Text.Length))}");
                }
            }

            // Get AddItem inside
            var addItems = FindRecursive<AddItem>(t);
            foreach (var ai in addItems)
            {
                Console.WriteLine($"    AddItem: {ai.Name}");
                foreach (var child in ai.Children.OfType<Item>().Take(10))
                {
                    Console.WriteLine($"      {child.Text}");
                }
            }
        }

        // Check CoreCompile for error context
        Console.WriteLine("\n=== CORECOMPILE TARGETS ===");
        foreach (var t in targets.Where(t => t.Name == "CoreCompile"))
        {
            var project = GetParentProject(t)?.Name ?? "unknown";
            Console.WriteLine($"  [{project}] CoreCompile - Children: {t.Children.Count}");
            foreach (var child in t.Children.Take(10))
            {
                Console.WriteLine($"    {child.GetType().Name}: {child}");
            }
        }

        // Find properties that indicate package references
        Console.WriteLine("\n=== LOOKING FOR PACKAGE REFERENCE PROPERTIES ===");
        var props = allNodes.OfType<Property>().Where(p => 
            p.Value?.Contains("Newtonsoft") == true ||
            p.Name?.Contains("PackageReference") == true
        ).ToList();
        foreach (var p in props.Take(20))
        {
            Console.WriteLine($"  {p.Name} = {p.Value?.Substring(0, Math.Min(200, p.Value.Length))}");
        }

        // Find message text containing PackageReference
        Console.WriteLine("\n=== MESSAGES WITH PackageReference ===");
        var pkgMsgs = allNodes.OfType<Message>().Where(m => m.Text?.Contains("PackageReference") == true).ToList();
        foreach (var m in pkgMsgs.Take(20))
        {
            var project = GetParentProject(m as BaseNode)?.Name ?? "unknown";
            Console.WriteLine($"  [{project}] {m.Text?.Substring(0, Math.Min(300, m.Text.Length))}");
        }
    }

    static List<T> FindRecursive<T>(TreeNode node) where T : BaseNode
    {
        var result = new List<T>();
        foreach (var child in node.Children)
        {
            if (child is T t) result.Add(t);
            if (child is TreeNode tn) result.AddRange(FindRecursive<T>(tn));
        }
        return result;
    }

    static void CollectAll(object node, List<object> result)
    {
        result.Add(node);
        if (node is TreeNode tn)
        {
            foreach (var child in tn.Children)
            {
                CollectAll(child, result);
            }
        }
    }

    static Project GetParentProject(BaseNode node)
    {
        if (node == null) return null;
        var current = node.Parent;
        while (current != null)
        {
            if (current is Project p) return p;
            current = (current as BaseNode)?.Parent;
        }
        return null;
    }
}
