        foreach (var m in pkgMsgs.Take(20))
        {
            var project = GetParentProject(m as BaseNode)?.Name ?? "unknown";
            Console.WriteLine($"  [{project}] {m.Text?.Substring(0, Math.Min(300, m.Text.Length))}");
        }
    }

    static List<T> FindRecursive<T>(TreeNode node) where T : BaseNode
    {
        var result = new List<T>();
        foreach (var child in node.Children)
        {
            if (child is T t) result.Add(t);
            if (child is TreeNode tn) result.AddRange(FindRecursive<T>(tn));
        }
        return result;
    }

    static void CollectAll(object node, List<object> result)
    {
        result.Add(node);
        if (node is TreeNode tn)
        {
            foreach (var child in tn.Children)
            {
                CollectAll(child, result);
            }
        }
    }

    static Project GetParentProject(BaseNode node)
    {
        if (node == null) return null;
        var current = node.Parent;
        while (current != null)
        {
            if (current is Project p) return p;
            current = (current as BaseNode)?.Parent;
        }
        return null;
    }
}
